import React from 'react';
import { Linking, Platform } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// Define your screens here (e.g., ProfileScreen and PaymentConfirmScreen)
const ProfileScreen = () => <Text>Profile Screen</Text>;
const PaymentConfirmScreen = () => <Text>Payment Confirm Screen</Text>;

const Stack = createStackNavigator();

const LinkingConfiguration = {
  initialRouteName: 'Profile',
  supportedUrls: [
    { scheme: 'myapp' },
  ],
};

export default function App() {
  const handleDeepLink = (url) => {
    Linking.parse(url).then((data) => {
      if (data.scheme === 'myapp') {
        switch (data.pathname) {
          case '/profile/:id':
            navigation.navigate('Profile', { id: data.params?.id });
            break;
          case '/payment/confirm':
            navigation.navigate('PaymentConfirm');
            break;
          default:
            console.log(`Unsupported URL: ${url}`);
        }
      }
    }).catch((error) => console.error(error));
  };

  const onUrlChange = (url) => {
    Linking.getInitialURL().then((initialUrl) => {
      if (initialUrl && url !== initialUrl) {
        handleDeepLink(initialUrl);
      }
    });

    Linking.addEventListener('url', handleDeepLink);

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  };

  const navigationRef = React.createRef();

  if (Platform.OS === 'ios') {
    Linking.configure({
      url: 'myapp://',
      screens: LinkingConfiguration,
    });

    return (
      <NavigationContainer ref={navigationRef} onUrlChange={onUrlChange}>
        {/* Add your navigator structure here */}
        <Stack.Navigator initialRouteName="Profile">
          <Stack.Screen name="Profile" component={ProfileScreen} />
          <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
        </Stack.Navigator>
      </NavigationContainer>
    );
  }

  return (
    <NavigationContainer ref={navigationRef}>
      {/* Add your navigator structure here */}
      <Stack.Navigator initialRouteName="Profile">
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}